  ('heelevel3-c5fb3965-moex-00005', 'heelevel3-c5fb3965', 'heelevel3-c5fb3965-moex-114-34cd00d7', 'sub-heelevel3-c5fb3965-02', NULL, 'essay', '甲男名下有 A 屋與 B 屋，甲喪偶，僅有一成年之獨子乙，為避免贈與
稅，將 A屋以通謀虛偽之意思表示賣給其子乙，並為所有權移轉登記。
甲又立親筆書寫之遺囑，內容為將 B屋遺贈給乙，記明年月日並親自簽
名後，至公證人處為密封遺囑，未料密封遺囑因見證人缺格而無效，嗣
甲死亡。試問：A屋與 B屋之所有權人為何？理由何在？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:36+00:00", "source_pdf_sha1": "612b410067d8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "204", "s": "0901", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則、親屬與繼承編", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "戶政"}'::jsonb, NULL),
  ('heelevel3-c5fb3965-moex-00006', 'heelevel3-c5fb3965', 'heelevel3-c5fb3965-moex-114-34cd00d7', 'sub-heelevel3-c5fb3965-02', NULL, 'essay', '甲男名下有 A屋，其將 A屋贈與給年滿 5 歲的乙子，於乙子滿 15歲時，
甲又將 A屋出售予丙並處分之，試問：甲乙之間之贈與契約與甲丙之間
的處分行為是否有效？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:36+00:00", "source_pdf_sha1": "612b410067d8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "204", "s": "0901", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則、親屬與繼承編", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "戶政"}'::jsonb, NULL),
  ('heelevel3-c5fb3965-moex-00007', 'heelevel3-c5fb3965', 'heelevel3-c5fb3965-moex-114-34cd00d7', 'sub-heelevel3-c5fb3965-02', NULL, 'essay', '甲男與乙女結婚後，婚後三年生有一子丙。甲為國際航空公司的機師，
經年忙於飛航，而由乙照顧丙之生活起居。因甲之職業關係，二人之感
情逐漸惡化，於婚後八年甲乙分居。丙與乙一同生活長達一年後，丙得
罕見之疾病，乙未得甲之同意，擅自欲將丙帶往國外治病，甲認為在國
內治病即可。二人為此爭執不下而訴請法院解決時，法院應如何決定？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:36+00:00", "source_pdf_sha1": "612b410067d8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "204", "s": "0901", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則、親屬與繼承編", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "戶政"}'::jsonb, NULL),
  ('heelevel3-c5fb3965-moex-00008', 'heelevel3-c5fb3965', 'heelevel3-c5fb3965-moex-114-34cd00d7', 'sub-heelevel3-c5fb3965-02', NULL, 'essay', '甲為被繼承人，有繼承人配偶乙與子女丙與丁。甲於繼承開始前，依法
立有一自書遺囑，將名下 A屋遺贈給其母戊，丙無意間發現該遺囑，遂
將其隱匿。其後甲復將該 A屋出賣給庚，甲於辦妥移轉登記後突發心臟
病死亡，留下財產 1200萬元。試問：甲之遺產應如何繼承？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:36+00:00", "source_pdf_sha1": "612b410067d8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "204", "s": "0901", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則、親屬與繼承編", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "戶政"}'::jsonb, NULL),
  ('heelevel3-c5fb3965-moex-00009', 'heelevel3-c5fb3965', 'heelevel3-c5fb3965-moex-114-3082b5f1', 'sub-heelevel3-c5fb3965-03', NULL, 'essay', '甲財團法人為辦理友善新住民活動，向 A市政府社會局申請補助新臺幣
（下同）二十萬元，A市政府檢核相關申請文件後，以 B函通知甲財團
法人通過補助，核發第一期補助款十萬元，並請甲財團法人舉辦活動後，
檢附相關支出憑證以辦理核銷，並於三個月後檢具第一期成果報告書，
經審查通過後再申請支付第二期補助款。不料甲財團法人檢具之支出憑
證不但未齊全，成果報告書之資料經查多處偽造不實，試問：A市政府
社會局應如何向甲財團法人要求返還已經支付之補助款十萬元，並不支
付第二期補助款？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:36+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "204", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "戶政"}'::jsonb, NULL),
  ('heelevel3-c5fb3965-moex-00010', 'heelevel3-c5fb3965', 'heelevel3-c5fb3965-moex-114-3082b5f1', 'sub-heelevel3-c5fb3965-03', NULL, 'essay', '一般認為法院應全面審查不確定法律概念的解釋與適用，僅在少數例外
情形，才適用判斷餘地理論。然而，為何要承認判斷餘地？是否存有判
斷餘地，該如何認定？有關核能發電廠之設置與運轉等許可行政行為，
應否承認行政機關享有判斷餘地，理由何在？試申述之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:36+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "204", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "戶政"}'::jsonb, NULL),
  ('heelevel3-c5fb3965-moex-00011', 'heelevel3-c5fb3965', 'heelevel3-c5fb3965-moex-114-3082b5f1', 'sub-heelevel3-c5fb3965-03', NULL, 'single_choice', '有關緊急命令之敘述，下列何者正確？', '["緊急命令之授權依據為一般法律", "緊急命令得暫時取代法律、變更法律", "緊急命令是由行政院院長發布", "緊急命令目的在於處理緊急危難或應付財經重大變故，故無須立法院之同意追認"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:36+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "204", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "戶政"}'::jsonb, NULL),
  ('heelevel3-c5fb3965-moex-00012', 'heelevel3-c5fb3965', 'heelevel3-c5fb3965-moex-114-3082b5f1', 'sub-heelevel3-c5fb3965-03', NULL, 'single_choice', '依行政程序法規定，關於行政指導之敘述，下列何者正確？', '["行政指導無須以特定人為對象", "行政指導具有法律上之強制力", "相對人若明確拒絕指導時，行政機關應即停止行政指導，並不得據此對相對人為不利之處置", "針對非其職權或職掌之事務，行政機關仍得為行政指導 21250–21350 22150 22950–23050 23250、23450"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:36+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "204", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "戶政"}'::jsonb, NULL)
